router.get('/fixed/search', (req, res) => {
  const q = req.query.q || '';
  // ✅ Parameterized — user input is data, not SQL
  const results = db.prepare(
    'SELECT id, name, price FROM products WHERE name LIKE ?'
  ).all(`%${q}%`);
  res.json({ results });
});
